parameters.jsCode:
// Calculate cost efficiency score
const billingData = $input.item.json.billing;
const prometheusData = $input.item.json.prometheus;
const dbData = $input.item.json.db;

const efficiencyScores = [];

for (const tenant of billingData) {
  const cost = tenant.total_cost;
  const cpuUsage = prometheusData.find(p => p.tenant === tenant.tenant)?.total_cpu_seconds || 0;
  const dbQueries = dbData.find(d => d.tenant === tenant.tenant)?.total_queries || 0;

  // Cost efficiency: cost per CPU second (lower is better)
  const costPerCpu = cpuUsage > 0 ? cost / cpuUsage : 0;

  // Cost efficiency: cost per DB query (lower is better)
  const costPerQuery = dbQueries > 0 ? cost / dbQueries : 0;

  // Overall efficiency score (normalized 0-100)
  const efficiencyScore = Math.max(0, 100 - (costPerCpu * 1000 + costPerQuery * 0.1));

  efficiencyScores.push({
    tenant: tenant.tenant,
    total_cost: cost,
    cpu_usage: cpuUsage,
    db_queries: dbQueries,
    cost_per_cpu: costPerCpu,
    cost_per_query: costPerQuery,
    efficiency_score: efficiencyScore
  });
}

return efficiencyScores.map(score => ({ json: score }));

// Build markdown report
const data = $input.all();

let report = `# Cost Attribution Report\n`;
report += `**Period**: Last 7 days\n`;
report += `**Generated**: ${new Date().toISOString()}\n\n`;

report += `## Cost Breakdown by Tenant\n\n`;
report += `| Tenant | Total Cost | CPU Usage | DB Queries | Cost/CPU sec | Cost/Query | Efficiency Score |\n`;
report += `|--------|------------|-----------|------------|-------------|------------|------------------|\n`;

for (const item of data) {
  const d = item.json;
  report += `| ${d.tenant} | $${d.total_cost.toFixed(2)} | ${d.cpu_usage.toFixed(0)} | ${d.db_queries.toFixed(0)} | $${d.cost_per_cpu.toFixed(4)} | $${d.cost_per_query.toFixed(6)} | ${d.efficiency_score.toFixed(1)}/100 |\n`;
}

report += `\n## Analysis\n\n`;

const overBudget = data.filter(d => d.efficiency_score < 50);
if (overBudget.length > 0) {
  report += `### ⚠️ Tenants with Low Efficiency Score (< 50)\n\n`;
  for (const tenant of overBudget) {
    report += `- **${tenant.tenant}**: Efficiency score ${tenant.efficiency_score.toFixed(1)}/100\n`;
  }
  report += `\n`;
}

const topEfficient = data.sort((a, b) => b.json.efficiency_score - a.json.efficiency_score).slice(0, 3);
report += `### ✅ Top 3 Most Efficient Tenants\n\n`;
for (const i = 0; i < topEfficient.length; i++) {
  report += `${i + 1}. **${topEfficient[i].json.tenant}**: ${topEfficient[i].json.efficiency_score.toFixed(1)}/100\n`;
}

return { json: { report } };

